mapper.select:
select ifnull(sum(case when a.status = 1 then 1 else 0 end), 0) as pending_count, ifnull(sum(case when a.status = 2 then 1 else 0 end), 0) as confirmed_count, ifnull(sum(case when a.status = 3 then 1 else 0 end), 0) as completed_count, ifnull(sum(case when a.status = 4 then 1 else 0 end), 0) as canceled_count from appointment a left join counselor_schedule cs on a.schedule_id = cs.id
and cs.schedule_date >= #{beginDate}
and cs.schedule_date <= #{endDate}

select u.name as name, count(*) as value from appointment a left join counselor c on a.counselor_id = c.id left join sys_user u on c.user_id = u.id left join counselor_schedule cs on a.schedule_id = cs.id
a.status != 4
and cs.schedule_date >= #{beginDate}
and cs.schedule_date <= #{endDate}
group by a.counselor_id, u.name order by value desc
